// src/components/Navbar.js
import React, { useState } from "react";
import { Link } from "react-router-dom";
import { Search, X, Menu } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import logo from "../assets/logo.png";

const pages = [
  { name: "Home", path: "/" },
  { name: "About", path: "/about" },
  { name: "Domains", path: "/domains" },
  { name: "Vision", path: "/vision" },
  { name: "Purpose", path: "/purpose" },
  { name: "Team", path: "/team" },
  { name: "Careers", path: "/careers" },
  { name: "Contact", path: "/contact" },
];

function Navbar({ onSearchClick }) {
  const [isMenuOpen, setIsMenuOpen] = useState(false);

  // Motion variants for staggered menu items
  const menuVariants = {
    hidden: { opacity: 0, x: 30 },
    visible: (i) => ({
      opacity: 1,
      x: 0,
      transition: { delay: i * 0.07, type: "spring", stiffness: 150, damping: 18 },
    }),
    exit: { opacity: 0, x: 30 },
  };

  return (
    <nav className="w-full bg-black text-yellow fixed top-0 z-50 shadow-md">
      <div className="max-w-7xl mx-auto px-6 md:px-10 flex justify-between items-center h-16">
        {/* Logo & Brand */}
        <div className="flex items-center space-x-2">
          <img src={logo} alt="Godemar Logo" className="w-10 h-10" />
          <span className="font-bold text-lg">Godemar’s Empire</span>
        </div>

        {/* Desktop Links */}
        <div className="hidden md:flex items-center space-x-6">
          {pages.map((page) => (
            <Link
              key={page.path}
              to={page.path}
              className="relative group font-medium transition"
            >
              {page.name}
              <span className="absolute left-0 -bottom-1 w-0 h-[2px] bg-yellow-500 transition-all duration-300 group-hover:w-full"></span>
            </Link>
          ))}
          {/* Search Button */}
          <button
            onClick={onSearchClick}
            className="ml-2 p-2 hover:text-yellow-500 focus:outline focus:outline-2 focus:outline-yellow-500 rounded transition"
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
        </div>

        {/* Mobile Hamburger */}
        <div className="md:hidden flex items-center">
          <button
            onClick={onSearchClick}
            className="mr-2 p-2"
            aria-label="Open search"
          >
            <Search size={20} />
          </button>
          <button
            onClick={() => setIsMenuOpen(!isMenuOpen)}
            aria-label="Toggle menu"
          >
            {isMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
      </div>

      {/* Mobile Menu + Backdrop */}
      <AnimatePresence>
        {isMenuOpen && (
          <>
            {/* Backdrop with blur */}
            <motion.div
              className="fixed inset-0 bg-black bg-opacity-50 backdrop-blur-sm md:hidden z-30"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              onClick={() => setIsMenuOpen(false)}
            />

            {/* Sliding Menu */}
            <motion.div
              initial={{ x: "100%" }}
              animate={{ x: 0 }}
              exit={{ x: "100%" }}
              transition={{ type: "spring", stiffness: 120, damping: 22 }}
              className="fixed top-0 right-0 h-full w-64 bg-black text-white shadow-lg md:hidden z-40 px-6 py-6 space-y-6"
            >
              <div className="flex justify-between items-center">
                <span className="font-bold text-lg">Menu</span>
                <button
                  onClick={() => setIsMenuOpen(false)}
                  className="p-2 hover:text-red-500 focus:outline focus:outline-2 focus:outline-red-500 rounded"
                  aria-label="Close menu"
                >
                  <X size={24} />
                </button>
              </div>
              <div className="flex flex-col space-y-4">
                {pages.map((page, i) => (
                  <motion.div
                    key={page.path}
                    custom={i}
                    initial="hidden"
                    animate="visible"
                    exit="exit"
                    variants={menuVariants}
                  >
                    <Link
                      to={page.path}
                      onClick={() => setIsMenuOpen(false)}
                      className="block hover:text-yellow-500 transition"
                    >
                      {page.name}
                    </Link>
                  </motion.div>
                ))}
              </div>
            </motion.div>
          </>
        )}
      </AnimatePresence>
    </nav>
  );
}

export default Navbar;
